var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"굴을 파고서 숨어있을 줄 알았더니…","JPN":"穴を掘って隠れていると思っていたが……","ENG":"I thought you would have dug a hole in the ground and hid...","TWN":"還以為你會挖個洞把自己藏起來。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"궁지에 몰린 생쥐가 먼저 머리를 들이밀 줄은 몰랐는걸?","JPN":"窮地に追い込まれたネズミが先に頭を突っこんでくるとはな。","ENG":"I did not expect a cornered mouse to rear her head out first.","TWN":"沒想到被逼到絕境的老鼠會先把頭伸出來？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"바람 좀 쐬러 왔어.","JPN":"少し風に当たろうと思ってね。","ENG":"I came out to get some fresh air.","TWN":"出來透透氣。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"이렇게 멀리까지 나오는 외출은 간만이네.","JPN":"こんなに遠くまで外出するのは久しぶりだわ。","ENG":"It has been eons since I last took a stroll this far out.","TWN":"好久沒出來這麼遠了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"악마 하나가 황금나무에 기생하여 인간성을 온존하고 있다고 들었건만…","JPN":"悪魔が一匹、黄金の木に寄生し人間性を保持していると聞いたが……","ENG":"I heard a devil was leeching off the Golden Tree to preserve her humanity...","TWN":"聽聞有個魔鬼寄生在黃金樹上，保留了人性…"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"구태여 여기까지 온 걸 보면, 결국 그 인간성을 내려놓기로 한 모양이구나.","JPN":"ここまで来たということは、もうそれを捨てたようだな。","ENG":"But seeing how you have ventured so far, it seems that you have chosen to let go of it.","TWN":"既然特意來到這裡，看來你最終還是放棄了那份人性。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왜지? 네 진정한 모습을 알게 된 인간들의 혐오 어린 시선에 지치기라도 한 거냐?","JPN":"何故だ？　貴様の真の姿を知った人間たちからの軽蔑の眼差しに耐えられなくなったか？","ENG":"What is your reasoning? Were you tired of the hateful gazes of humans after they found out your true identity?","TWN":"為什麼呢？是不是厭倦了人們得知你真面目後的厭惡目光呢？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"…그래, 지쳐서 떠났어.","JPN":"……そうよ。疲れて村を出たの。","ENG":"...Yes, I left because I was tired.","TWN":"…是啊，累了，所以離開了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"이제 앞으론, 태어날 인간들에게 항상 내가 못된 악마가 아니란 걸 설득해야 할 테니까.","JPN":"これからは新しく生まれてくる人間たちもアタシが悪い悪魔じゃないと説得する必要があるでしょう？","ENG":"Because now, I will have to convince the newborns that I am not an evil devil.","TWN":"以後，我還得一直向新生的人類解釋我不是個壞魔鬼。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"쓸데없는 걱정이군.","JPN":"余計な心配だな。","ENG":"What useless worrying.","TWN":"真是無謂的煩惱。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"이 세계의 인류사는 떠오르지 않을 태양과 함께 종식되고, 영원히 잊혀질 거다.","JPN":"この世界の人類史は昇らぬ太陽と共に終息し、永遠に忘れ去られることとなる。","ENG":"Human history of this world ends with the unrising sun. Then, it will be forgotten forever.","TWN":"這個世界的人類歷史，將隨著不再升起的太陽而終結，並被永遠遺忘。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"내 동생이 그렇게 원했으니까.","JPN":"余の妹がそう望んでいるのだ。","ENG":"That is what my sister wanted.","TWN":"因為我的妹妹就是這麼希望的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"훗, 동생이라.","JPN":"ふっ、妹ね。","ENG":"Pfft, your sister.","TWN":"呵，妹妹嗎。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"타기리온의 권능으로 만들어진 인형 껍데기 주제에…","JPN":"タギリオンの権能で作られた人形のくせに……","ENG":"You are merely a puppet made from the power of Thagirion.","TWN":"不過是用塔基里翁的權能製造的魁儡…"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"살아있는 인간처럼 자매 흉내라도 내는 거니?","JPN":"人間みたいに、姉妹ごっこでもしているの？","ENG":"So are you pretending to be her sister as if you were a living human?","TWN":"是在模仿活生生的人類玩扮家家酒嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"정곡을 찔렸나봐?","JPN":"図星だったようね。","ENG":"Did I hit too close to home?","TWN":"正中要害了嗎？"},"stage":{"bg":"ROOT_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"황금나무의 힘을 빌려 막은 건가?","JPN":"黄金の木の力を借りて止めたのか？","ENG":"Borrowing the power of the Golden Tree to block my attack?","TWN":"是借助了黃金樹的力量擋住的嗎？"},"stage":{"bg":"ROOT_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"악마치고는 제법이군.","JPN":"悪魔のくせにやるではないか。","ENG":"Clever for a devil.","TWN":"雖然是魔鬼，但還不錯。"},"stage":{"bg":"ROOT_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"같은 악마라고 해서 네 졸개가 된 줏대 없는 놈과 비교하면 곤란하지.","JPN":"同じ悪魔だからって、アナタの手下になった優柔不断なやつらと一緒にしないでちょうだい。","ENG":"Do not think that all devils are the same as your spineless underlings.","TWN":"魔鬼之間，也是有所區別的，別拿我和你那個沒有骨氣的手下相比。"},"stage":{"bg":"ROOT_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"황금나무가 요정을 낳았다면, 난 그 중에서도 첫째거든.","JPN":"黄金の木が妖精を産んだとしたら、アタシはその中の長女よ。","ENG":"If the Golden Tree gave birth to fairies, I am the eldest of them.","TWN":"如果說黃金樹孕育了精靈，那我就是其中的長子。"},"stage":{"bg":"ROOT_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"너의 그 힘은 분명, 황금나무의 은총을 빌려 얻은 권능일 터.","JPN":"貴様のその力はおそらく、黄金の木の恩を借りて得た権能であろう。","ENG":"That power of yours is most certainly borrowed from the Golden Tree's grace.","TWN":"你的那股力量，一定是借助了黃金樹的恩賜才獲得的權能。"},"stage":{"bg":"ROOT_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"온전치 못한 황금나무도 곧 그 그릇의 한계를 드러내겠지.","JPN":"まともではない黄金の木もすぐその器に限界が来るだろう。","ENG":"The imperfect Golden Tree will soon reveal its limit.","TWN":"不完整的黃金樹很快就會顯露出它的極限。"},"stage":{"bg":"ROOT_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그것보다 네 검이 먼저 부러지지 않을까?","JPN":"それより、アナタの剣が先に折れてしまうんじゃないかしら。","ENG":"Do you not think that your sword will break before that?","TWN":"比起那個，你的劍會不會先斷掉呢？"},"stage":{"bg":"ROOT_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"이리 오렴, 마왕의 사도야.","JPN":"おいで、魔王の使徒。","ENG":"Come hither, Apostle of the Demon Lord.","TWN":"過來吧，魔王的使徒。"},"stage":{"bg":"ROOT_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"악마가 어떤 존재인지…","JPN":"悪魔がどんな存在なのか……","ENG":"I will engrave in that thick doll head of yours...","TWN":"讓你見識一下魔鬼是什麼樣的存在…"},"stage":{"bg":"ROOT_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 딱딱한 인형 머리에 또렷이 새겨줄 테니까.","JPN":"その固い人形の頭にはっきりと刻み付けてあげるわ。","ENG":"what a devil truly is.","TWN":"我會在你那堅硬的魁儡腦袋上一筆一劃刻下來。"},"stage":{"bg":"ROOT_03","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};